import createClient from "openapi-fetch";
import type { paths, components } from "@/types/adoptiumApiTypes";
import type {
  paths as marketplacePaths,
  components as marketplaceComponents,
} from "@/types/marketplaceApiTypes";

export const ADOPTIUM_API_BASE = "https://api.adoptium.net";
export const MARKETPLACE_API_BASE = "https://marketplace-api.adoptium.net";

// Typed client backed by the generated OpenAPI paths
const adoptiumClient = createClient<paths>({ baseUrl: ADOPTIUM_API_BASE });
const marketplaceClient = createClient<marketplacePaths>({
  baseUrl: MARKETPLACE_API_BASE,
});

// Re-export useful schema types for consumers
export type { components };
export type Release = components["schemas"]["Release"];
export type MarketplaceBinaryAssetView =
  marketplaceComponents["schemas"]["BinaryAssetView"];
export type MarketplaceVendor = marketplaceComponents["schemas"]["Vendor"];
export type BinaryAssetView = components["schemas"]["BinaryAssetView"];
export type Attestation = components["schemas"]["Attestation"];
export type ReleaseType = components["schemas"]["ReleaseType"];
export type Architecture = components["schemas"]["Architecture"];
export type OperatingSystem = components["schemas"]["OperatingSystem"];
export type ImageType = components["schemas"]["ImageType"];

// ---------------------------------------------------------------------------
// Assets / Releases
// ---------------------------------------------------------------------------

/**
 * getLatestAssets — GET /v3/assets/latest/{feature_version}/{jvm_impl}
 * Returns latest assets for the given feature version.
 */
export async function fetchLatestAssets(
  version: number | string,
  params: {
    os?: OperatingSystem;
    architecture?: Architecture;
    image_type?: ImageType;
  } = {},
): Promise<BinaryAssetView[]> {
  const feature_version =
    typeof version === "string" ? parseInt(version, 10) : version;
  const { data, error } = await adoptiumClient.GET(
    "/v3/assets/latest/{feature_version}/{jvm_impl}",
    {
      params: {
        path: { feature_version, jvm_impl: "hotspot" },
        query: {
          vendor: "eclipse",
          ...params,
        },
      },
    },
  );
  if (error) throw error;
  return data ?? [];
}

/**
 * searchReleases — GET /v3/assets/feature_releases/{feature_version}/{release_type}
 * Returns release information for a feature version.
 */
export async function fetchFeatureReleases(
  version: number,
  releaseType: ReleaseType,
  params: {
    architecture?: Architecture;
    os?: OperatingSystem;
    image_type?: ImageType;
    page?: number;
    page_size?: number;
    before?: string;
    show_page_count?: boolean;
  } = {},
): Promise<{ data: Release[]; pagecount: number }> {
  const { data, error, response } = await adoptiumClient.GET(
    "/v3/assets/feature_releases/{feature_version}/{release_type}",
    {
      params: {
        path: { feature_version: version, release_type: releaseType },
        query: { vendor: "eclipse", ...params },
      },
    },
  );
  if (error) throw error;
  const pagecount = Number(
    response.headers.get("pagecount") ?? response.headers.get("PageCount") ?? 0,
  );
  return { data: data ?? [], pagecount };
}

// ---------------------------------------------------------------------------
// Release Notes
// ---------------------------------------------------------------------------

/**
 * getReleaseNotes — GET /v3/info/release_notes/{release_name}
 */
export async function fetchReleaseNotes(
  release_name: string,
): Promise<unknown> {
  const { data, error } = await adoptiumClient.GET(
    "/v3/info/release_notes/{release_name}",
    { params: { path: { release_name } } },
  );
  if (error) throw error;
  return data;
}

/**
 * getReleaseNames — GET /v3/info/release_names
 * Returns the most recent LTS release name (first result).
 */
export async function fetchLatestReleaseName(): Promise<string | null> {
  try {
    const { data, error } = await adoptiumClient.GET("/v3/info/release_names", {
      params: {
        query: {
          heap_size: "normal",
          image_type: "jdk",
          lts: true,
          page: 0,
          page_size: 1,
          project: "jdk",
          release_type: "ga",
          semver: false,
          sort_method: "DEFAULT",
          sort_order: "DESC",
          vendor: "eclipse",
        },
      },
    });
    if (error) return null;
    const releases = (data as { releases?: string[] })?.releases;
    return releases?.[0] ?? null;
  } catch {
    return null;
  }
}

