/**
 * getOperatingSystems — GET /v3/types/operating_systems
 */
export async function fetchOperatingSystems(
  signal?: AbortSignal,
): Promise<string[]> {
  const { data, error } = await adoptiumClient.GET(
    "/v3/types/operating_systems",
    { signal },
  );
  if (error) throw error;
  return (data as string[]) ?? [];
}

/**
 * getArchitectures — GET /v3/types/architectures
 */
export async function fetchArchitectures(
  signal?: AbortSignal,
): Promise<string[]> {
  const { data, error } = await adoptiumClient.GET("/v3/types/architectures", {
    signal,
  });
  if (error) throw error;
  return (data as string[]) ?? [];
}

// ---------------------------------------------------------------------------
// Attestations
// ---------------------------------------------------------------------------

/**
 * listAttestationsForRelease — GET /v3/attestations/release_name/{release_name}
 */
export async function fetchAttestations(
  release_name: string,
  project: components["schemas"]["project"] = "jdk",
): Promise<Attestation[]> {
  const { data, error, response } = await adoptiumClient.GET(
    "/v3/attestations/release_name/{release_name}",
    {
      params: {
        path: { release_name },
        query: { project },
      },
    },
  );
  // 404 means no attestations exist for this release — not an error
  if (response.status === 404) return [];
  if (error) throw error;
  return data ?? [];
}

// ---------------------------------------------------------------------------
// Download Statistics
// (Not in the OpenAPI spec — kept as a raw fetch call)
// ---------------------------------------------------------------------------

/** GET /v3/stats/downloads/total/{release}[/{subpath}] */
export async function fetchDownloadStats(
  release: string,
  subpath = "",
): Promise<Record<string, number> | null> {
  const url = `${ADOPTIUM_API_BASE}/stats/downloads/total/${release}${subpath ? "/" + subpath : ""}`;
  const res = await fetch(url);
  if (!res.ok) return null;
  return res.json() as Promise<Record<string, number>>;
}

// ---------------------------------------------------------------------------
// Marketplace
// (Separate API — not covered by the Adoptium OpenAPI spec)
// ---------------------------------------------------------------------------

export interface MarketplaceQueryParams {
  version: number;
  os?: marketplaceComponents["schemas"]["OperatingSystem"];
  architecture?: marketplaceComponents["schemas"]["Architecture"];
  package_type?: marketplaceComponents["schemas"]["ImageType"];
  vendors?: MarketplaceVendor[];
}

/** latestForVendors — GET /v1/assets/latestForVendors */
export async function fetchMarketplaceReleases(
  params: MarketplaceQueryParams,
): Promise<MarketplaceBinaryAssetView[] | null> {
  try {
    const { data, error } = await marketplaceClient.GET(
      "/v1/assets/latestForVendors",
      {
        params: {
          query: {
            feature_version: [params.version],
            vendor: params.vendors ?? [],
            ...(params.os && params.os !== ("any" as string)
              ? { os: [params.os] }
              : {}),
            ...(params.architecture && params.architecture !== ("any" as string)
              ? { architecture: [params.architecture] }
              : {}),
            ...(params.package_type && params.package_type !== ("any" as string)
              ? { image_type: [params.package_type] }
              : {}),
          },
        },
      },
    );
    if (error) return null;
    return data ?? null;
  } catch {
    return null;
  }
}
